#include<bits/stdc++.h>
using namespace std;
long long lst[500010][210],s[500010],f[500010],g[500010];
double slope(long long a,long long b)
{
    long long ax=-s[a];
    long long bx=-s[b];
    long long ay=g[a]-s[a]*s[a];
    long long by=g[b]-s[b]*s[b];
    if(ax==bx)
    {
        return -1e18;
    }
    return (by-ay)*1.0/(bx-ax);
}
int main()
{
    long long n,k;
    scanf("%lld%lld",&n,&k);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&s[i]);
        s[i]+=s[i-1];
    }
    for(long long p=1;p<=k;p++)
    {
        memcpy(g,f,sizeof(f));
        deque<long long> q;
        for(long long i=1;i<=n;i++)
        {
            while(q.size()>1&&slope(q[0],q[1])<=(double)s[i])
            {
                q.pop_front();
            }
            f[i]=0;
            if(!q.empty())
            {
                long long pre=q.front();
                f[i]=g[pre]+s[pre]*(s[i]-s[pre]);
                lst[i][p]=pre;
            }
            while(q.size()>1&&slope(q.back(),q[q.size()-2])>=slope(i,q.back()))
            {
                q.pop_back();
            }
            q.push_back(i);
        }
    }
    printf("%lld\n",f[n]);
    for(long long i=lst[n][k];i>=1;i=lst[i][--k])
    {
        printf("%lld ",i);
    }
    return 0;
}
